import{_ as s,c as n,o as e,aj as i}from"./chunks/framework.VtnL2jmu.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"springboot/Linux下SpringBoot项目启动.md","filePath":"springboot/Linux下SpringBoot项目启动.md"}'),t={name:"springboot/Linux下SpringBoot项目启动.md"};function p(r,a,o,l,g,c){return e(),n("div",null,[...a[0]||(a[0]=[i(`<h2 id="linux下springboot项目启动" tabindex="-1">Linux下SpringBoot项目启动 <a class="header-anchor" href="#linux下springboot项目启动" aria-label="Permalink to “Linux下SpringBoot项目启动”">​</a></h2><h3 id="一、-核心工具-maven-wrapper-mvnw" tabindex="-1">一、 核心工具：Maven Wrapper (<code>mvnw</code>) <a class="header-anchor" href="#一、-核心工具-maven-wrapper-mvnw" aria-label="Permalink to “一、 核心工具：Maven Wrapper (mvnw)”">​</a></h3><p><strong>什么是 <code>mvnw</code>？</strong></p><p>它是项目的“环境保姆”。一个 Shell 脚本，允许你在<strong>不安装全局 Maven</strong> 的情况下运行 Maven 命令。</p><p><strong>核心优势：</strong></p><ul><li><strong>零安装</strong>：只需 JDK，脚本会自动下载匹配版本的 Maven。</li><li><strong>版本一致性</strong>：确保开发、测试、生产环境使用完全相同的 Maven 版本。</li><li><strong>环境隔离</strong>：不同项目可以使用不同版本的 Maven，互不干扰。</li></ul><hr><h3 id="二、-快速启动三部曲" tabindex="-1">二、 快速启动三部曲 <a class="header-anchor" href="#二、-快速启动三部曲" aria-label="Permalink to “二、 快速启动三部曲”">​</a></h3><p>进入项目根目录后，执行以下操作：</p><ol><li><p><strong>赋予执行权限</strong>（克隆后的文件默认可能无权限）：</p><p>Bash</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>chmod +x mvnw</span></span></code></pre></div></li><li><p><strong>清理并运行</strong>：</p><p>Bash</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>./mvnw clean spring-boot:run</span></span></code></pre></div></li><li><p><strong>生产环境打包运行</strong>：</p><p>Bash</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span># 打包并跳过测试</span></span>
<span class="line"><span>./mvnw clean package -DskipTests</span></span>
<span class="line"><span># 后台持续运行</span></span>
<span class="line"><span>nohup java -jar target/*.jar &gt; server.log 2&gt;&amp;1 &amp;</span></span></code></pre></div></li></ol><hr><h3 id="三、-常见编译错误-java-版本冲突" tabindex="-1">三、 常见编译错误：Java 版本冲突 <a class="header-anchor" href="#三、-常见编译错误-java-版本冲突" aria-label="Permalink to “三、 常见编译错误：Java 版本冲突”">​</a></h3><p><strong>错误现象：</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Source option 5 is no longer supported. Use 7 or later.</span></span></code></pre></div><p><strong>根本原因：</strong></p><p>Maven 默认编译器版本太老（回退到了 Java 5），而现代 JDK（如 JDK 17/21）已不再支持该版本。</p><p><strong>解决方案：</strong></p><p>在 <code>pom.xml</code> 中显式指定编译器版本，确保其与系统安装的 JDK 版本一致。</p><p>XML</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>&lt;properties&gt;</span></span>
<span class="line"><span>    &lt;java.version&gt;17&lt;/java.version&gt; &lt;!-- 必须与系统 java -version 一致 --&gt;</span></span>
<span class="line"><span>    &lt;project.build.sourceEncoding&gt;UTF-8&lt;/project.build.sourceEncoding&gt;</span></span>
<span class="line"><span>    &lt;!-- 显式覆盖，解决兼容性报错 --&gt;</span></span>
<span class="line"><span>    &lt;maven.compiler.source&gt;\${java.version}&lt;/maven.compiler.source&gt;</span></span>
<span class="line"><span>    &lt;maven.compiler.target&gt;\${java.version}&lt;/maven.compiler.target&gt;</span></span>
<span class="line"><span>&lt;/properties&gt;</span></span></code></pre></div><hr><h3 id="四、-进阶开发技巧" tabindex="-1">四、 进阶开发技巧 <a class="header-anchor" href="#四、-进阶开发技巧" aria-label="Permalink to “四、 进阶开发技巧”">​</a></h3><ul><li><p><strong>指定端口启动</strong>：</p><p><code>./mvnw spring-boot:run -Dspring-boot.run.arguments=&quot;--server.port=9090&quot;</code></p></li><li><p><strong>Git 管理</strong>：</p><p><code>mvnw</code>、<code>mvnw.cmd</code> 以及 <code>.mvn/</code> 目录<strong>必须提交</strong>到 Git 仓库，这是实现“开箱即用”的关键。</p></li><li><p><strong>临时切换 JDK</strong>：</p><p>如果系统有多个 JDK，可以临时指定：</p><p><code>JAVA_HOME=/path/to/jdk-17 ./mvnw spring-boot:run</code></p></li></ul><hr><h3 id="五、-开发者心得" tabindex="-1">五、 开发者心得 <a class="header-anchor" href="#五、-开发者心得" aria-label="Permalink to “五、 开发者心得”">​</a></h3><p>将“环境配置”转化为“代码（Wrapper）”是现代 Java 开发的最佳实践。它不仅简化了部署流程，也极大地降低了团队协作时环境搭建的沟通成本。</p>`,26)])])}const b=s(t,[["render",p]]);export{h as __pageData,b as default};
